import { createIdentityClient } from "@sge/aether-identity";

const identity = createIdentityClient({
  baseUrl: "https://api.skygenesisenterprise.com",
  clientId: process.env.SGE_CLIENT_ID ?? "",
  redirectUri: "https://app.example.com/callback",
});

const authorizationUrl = await identity.authorizationUrl({
  scope: ["openid", "profile", "email"],
  state: crypto.randomUUID(),
});

console.log(authorizationUrl);
